{
  "game_identity": {
    "observed_title": "CASTLE CLASHERS",
    "genre": "Physics-based Artillery Strategy",
    "camera_and_orientation": "2D side-scrolling, portrait orientation",
    "visual_style": "Cartoonish, 2D vector art with physics-based destruction"
  },
  "core_loop": {
    "one_sentence": "Players aim and fire various projectiles from their mobile castle to destroy the opponent's castle before their own is destroyed.",
    "player_goal": "Reduce the enemy castle's health to 0% by hitting it with projectiles.",
    "failure_or_pressure": "The enemy castle fires back, reducing the player's castle health.",
    "why_it_is_fun": "Satisfying physics destruction, tactical aiming, and discovering different projectile types."
  },
  "player_controls": [
    {
      "gesture": "Drag and release",
      "target": "Characters inside the player's castle",
      "result": "Displays a trajectory line while dragging, and fires a projectile upon release.",
      "evidence_timestamps": [
        "00:04",
        "00:14",
        "00:29",
        "00:41"
      ],
      "confidence": "high"
    }
  ],
  "visible_ui": [
    {
      "element": "Health Bars and Percentages",
      "location": "Top left (Player/Blue) and Top right (Enemy/Red)",
      "purpose": "Indicates the remaining health of each castle.",
      "evidence_timestamps": [
        "00:00",
        "00:53"
      ]
    },
    {
      "element": "VS Graphic",
      "location": "Top center",
      "purpose": "Emphasizes the competitive nature of the game.",
      "evidence_timestamps": [
        "00:00",
        "00:53"
      ]
    },
    {
      "element": "Play Button",
      "location": "Bottom center (End screen)",
      "purpose": "Call to action to download or play the game.",
      "evidence_timestamps": [
        "00:54",
        "00:56"
      ]
    }
  ],
  "timeline_beats": [
    {
      "time_range": "00:00-00:03",
      "event": "Enemy attacks player's castle",
      "gameplay_meaning": "Establishes the threat and the turn-based or continuous attack nature of the game.",
      "playable_relevance": "Good hook to show the player they are under attack and need to respond."
    },
    {
      "time_range": "00:04-00:09",
      "event": "Player aims and fires a single rocket",
      "gameplay_meaning": "Introduces the core aiming mechanic and basic attack.",
      "playable_relevance": "The primary interaction the user will perform."
    },
    {
      "time_range": "00:14-00:24",
      "event": "Player uses a different character to fire multiple rockets",
      "gameplay_meaning": "Shows variety in attacks and characters.",
      "playable_relevance": "Demonstrates depth and strategy; different units have different abilities."
    },
    {
      "time_range": "00:29-00:36",
      "event": "Player uses a goblin to fire an explosive bomb",
      "gameplay_meaning": "Further showcases unit variety and different destruction effects.",
      "playable_relevance": "Keeps the gameplay loop interesting with varied visual feedback."
    },
    {
      "time_range": "00:54-00:56",
      "event": "End card appears",
      "gameplay_meaning": "Game over/Ad complete state.",
      "playable_relevance": "Standard CTA screen."
    }
  ],
  "mechanics": [
    {
      "name": "Slingshot Aiming",
      "description": "Dragging from a character creates a dotted trajectory line indicating where the projectile will go.",
      "evidence_timestamps": [
        "00:04",
        "00:15",
        "00:30",
        "00:42"
      ],
      "implementation_priority": "must"
    },
    {
      "name": "Physics Destruction",
      "description": "Castles are composed of blocks/sections that break apart, fall, and disappear when hit by projectiles.",
      "evidence_timestamps": [
        "00:01",
        "00:08",
        "00:18",
        "00:33"
      ],
      "implementation_priority": "must"
    },
    {
      "name": "Unit Types",
      "description": "Different characters fire different projectiles (e.g., single rocket, multi-rocket, bomb).",
      "evidence_timestamps": [
        "00:06",
        "00:16",
        "00:31"
      ],
      "implementation_priority": "should"
    },
    {
      "name": "Character Death",
      "description": "When a section of the castle containing a character is destroyed, the character turns into a tombstone.",
      "evidence_timestamps": [
        "00:09",
        "00:41"
      ],
      "implementation_priority": "could"
    }
  ],
  "feedback_and_juice": [
    {
      "trigger": "Projectile hits castle",
      "visual_or_audio_feedback": "Explosions, smoke, flying debris, screen shake, and floating damage numbers (e.g., -140, -44).",
      "importance": "must"
    },
    {
      "trigger": "Aiming",
      "visual_or_audio_feedback": "Dotted trajectory line updates in real-time based on drag position.",
      "importance": "must"
    },
    {
      "trigger": "Projectile in flight",
      "visual_or_audio_feedback": "Smoke trails following the rockets/bombs.",
      "importance": "should"
    },
    {
      "trigger": "Health reduction",
      "visual_or_audio_feedback": "Health bar decreases and percentage text updates dynamically.",
      "importance": "must"
    }
  ],
  "playable_minimum": {
    "must_include": [
      "Drag-to-aim trajectory mechanic",
      "At least one type of projectile to fire",
      "Basic destructible enemy castle",
      "Health bars for win/loss condition"
    ],
    "can_simplify": [
      "Complex physics destruction can be simplified to pre-fractured chunks or simple health-based state changes for castle sections",
      "Reduce the number of playable characters to 1 or 2 for a shorter ad experience"
    ],
    "should_avoid": [
      "Complex enemy AI; enemy can just fire on a simple timer",
      "Moving the castles (tracks are visible but castles remain stationary in the video)"
    ]
  },
  "variation_hooks": [
    {
      "parameter": "Projectile Type",
      "effect": "Changes the visual effect and damage pattern (e.g., single heavy hit vs. spread damage).",
      "safe_range_or_values": "1 to 3 distinct types"
    },
    {
      "parameter": "Enemy Castle Layout",
      "effect": "Alters the optimal aiming strategy for the player.",
      "safe_range_or_values": "2 to 3 different structural designs"
    }
  ],
  "open_questions_or_assumptions": [
    "Are the castles supposed to move? They have tank treads, but remain stationary throughout the clip.",
    "Is the enemy's targeting random, or does it aim at specific weak points/characters?",
    "Does the player choose which character to use, or is it a set sequence? The video shows the player selecting different characters."
  ]
}
